import React from 'react';
import { render } from '@testing-library/react';
import { ThemeProvider } from '../ThemeProvider';
import path from 'path';
import fs from 'fs';
const originalIconsDir = path.resolve(path.dirname(require.resolve('@universe-design/icons/package.json')), 'icons');
const LightProviders = ({ children }) => (React.createElement(ThemeProvider, { mode: "light" }, children));
const DarkProviders = ({ children }) => (React.createElement(ThemeProvider, { mode: "dark" }, children));
function getName(file) {
    const obj = path.parse(file);
    const fileName = obj.name.replace(/-dm$/, '');
    const parts = fileName.split(/[-_]/g);
    const theme = parts[parts.length - 1];
    const componentName = parts
        .map((word) => {
        if (word === 'icon') {
            return '';
        }
        return word[0].toUpperCase() + word.slice(1);
    })
        .join('');
    return { theme, componentName, fileName };
}
const entries = fs.readdirSync(originalIconsDir).map((file) => {
    const { componentName, ...rest } = getName(file);
    return [componentName, { componentName, file, ...rest }];
});
const entriesMap = Object.fromEntries(entries);
console.log(originalIconsDir);
function getPath(p = '') {
    return path.resolve(__dirname, '../icons', p);
}
// function readSourceSVG(file: string) {
//   return fs.readFileSync(path.resolve(originalIconsDir, file), {
//     encoding: 'utf-8',
//   })
// }
fs.readdirSync(getPath())
    .filter((file) => {
    const name = path.basename(file, '.tsx');
    const entry = entriesMap[name];
    return entry && entry.theme === 'colorful';
})
    .forEach((file) => {
    test(file, () => {
        // const name = path.basename(file, '.tsx')
        // const entry = entriesMap[name]
        // eslint-disable-next-line @typescript-eslint/no-require-imports
        const Component = require(getPath(file)).default;
        const { container } = render(React.createElement(Component, null), {
            wrapper: LightProviders,
        });
        expect(container.firstChild).toMatchSnapshot();
        //   expect(container.firstChild?.firstChild).toMatchInlineSnapshot(
        //     prettier.format(readSourceSVG(`${entry.fileName}.svg`), {
        //       parser: 'babel',
        //     })
        //   )
        const { container: containerDark } = render(React.createElement(Component, null), {
            wrapper: DarkProviders,
        });
        expect(containerDark.firstChild).toMatchSnapshot();
        //   expect(containerDark.firstChild?.firstChild).toMatchInlineSnapshot(
        //     prettier.format(readSourceSVG(`${entry.fileName}-dm.svg`), {
        //       parser: 'babel',
        //     })
        //   )
    });
});
